// DeploymentServiceServer is the server API for DeploymentService service.
// All implementations should embed UnimplementedDeploymentServiceServer
// for forward compatibility.
//
// DeploymentService is the operator-facing surface for engine-on-
// instance lifecycle. Locked by docs/design/0002-deploy.md.
//
// The verb is `deploy` (imperative name, declarative semantics):
// re-running with the same (image, model) on a matching container is
// a no-op. Drift triggers a re-deploy. The service implements the
// failure-mode contract from the design doc: idempotency lookup, state-
// file hygiene, instance-gone-is-hard-error.
//
// All five RPCs return UNIMPLEMENTED in the PR that introduces this
// service -- the executor (SSH+docker) lands in a follow-up Phase 2
// PR. The interface is committed here so subsequent PRs slot in
// without proto churn.
type DeploymentServiceServer interface {
	// CreateDeployment runs the full idempotency + state-hygiene contract.
	// Re-running with the same id against a matching container is a no-op
	// (already_existed=true). If the container drifted or is missing,
	// the executor reconciles.
	CreateDeployment(context.Context, *CreateDeploymentRequest) (*CreateDeploymentResponse, error)
	// DescribeDeployment returns the current view of one deployment. The
	// record is the state-file view (the engine's live state is read via
	// the executor's docker inspect when the operator queries via the CLI's
	// status verb).
	DescribeDeployment(context.Context, *DescribeDeploymentRequest) (*DescribeDeploymentResponse, error)
	// ListDeployments enumerates deployments. Optional filter by
	// instance_id (all deployments on a given Instance) or state.
	ListDeployments(context.Context, *ListDeploymentsRequest) (*ListDeploymentsResponse, error)
	// DestroyDeployment stops the container and patches the record to
	// TERMINATED. Idempotent: destroying an already-terminated id is a
	// no-op.
	DestroyDeployment(context.Context, *DestroyDeploymentRequest) (*DestroyDeploymentResponse, error)
	// WatchDeployment streams state transitions for one deployment until
	// a terminal state (TERMINATED or FAILED) is reached or the client
	// disconnects. Events carry the from/to states + a free-form phase
	// string + progress message. Clients who need the full Deployment
	// record at any point call DescribeDeployment between events.
	//
	// Logs are NOT carried on this stream -- they are a separate concern
	// (see the followup issue for `iplane deployment logs <id> [-f]`).
	WatchDeployment(*WatchDeploymentRequest, grpc.ServerStreamingServer[DeploymentStateChangedEvent]) error
	// TouchDeployment explicitly marks the deployment as active --
	// updates last_activity_at to "now", resetting the idle-TTL
	// reaper's clock. v0.2 ch7-beat1.7 callers:
	//
	//   - The router (per inference request, after the lookup picks
	//     the target deployment). The router is the canonical data-
	//     plane source of activity.
	//   - The operator's `iplane deployment touch` CLI verb (#71),
	//     for the "I'm still using this deployment; don't reap yet"
	//     escape hatch when traffic is intermittent.
	//
	// Explicit-touch on its own RPC rather than as a side effect of
	// DescribeDeployment or WatchDeployment: passive inspection
	// (operator running `iplane deployment describe` to check state)
	// must not extend the lease, or the reaper is useless.
	TouchDeployment(context.Context, *TouchDeploymentRequest) (*TouchDeploymentResponse, error)
	// ScaleDeployment changes the replica count of a running deployment.
	// v0.2 ch7-beat3.8 (#86) ships scale-up only: target_replicas > the
	// current count appends new replicas by extending the slot numbering
	// (deployment with r0,r1,r2 scaled to 5 gains r3,r4 -- existing slots
	// are not touched, even if they're DEGRADED tombstones from a prior
	// fan-out partial failure). Scale-down (target < current) returns
	// UNIMPLEMENTED with a pointer to #145 where the drain-and-destroy
	// semantics get designed.
	//
	// target == current is a no-op and returns the current record
	// unchanged. target <= 0 is invalid.
	ScaleDeployment(context.Context, *ScaleDeploymentRequest) (*ScaleDeploymentResponse, error)
}

